command:
mkdir -p .claude-tdd-pro/space space && printf '{"id":"m-act","dimension":"activity","value":1}
{"id":"m-perf","dimension":"performance","value":2}
' > .claude-tdd-pro/space/collected.jsonl && printf 'dimensions:
  activity: {opt_in: true, enabled: false}
  performance: {enabled: true}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-export.sh" --collected .claude-tdd-pro/space/collected.jsonl --out export.json --config space/config.yaml 2>err.txt && ! grep -q 'm-act' export.json && grep -q 'm-perf' export.json && echo ok 1>&2
